SELECT company_name, NTILE(3) OVER (ORDER BY company_name) AS group_number
FROM companies
ORDER BY group_number, company_name;

SELECT COUNT(DISTINCT contact_id) AS unique_users_count
FROM contact_roles
WHERE role_id = 2;

SELECT companies.company_id, companies.company_name, contacts.first_name, contacts.last_name, contacts.address, contacts.email, contacts.phone_number
FROM companies
LEFT JOIN contacts ON companies.company_id = contacts.company_id;
